const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');
require('dotenv').config();

const app = express();
const port = 3000;

const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

// Proxy configuration
const premblyProxy = createProxyMiddleware({
  target: 'https://api.prembly.com',
  changeOrigin: true,
  pathRewrite: {
    '^/api/prembly': '', // Remove /api/prembly from the request path
  },
  onProxyReq: (proxyReq, req, res) => {
    // Inject Prembly credentials
    if (PREMBLY_APP_ID) {
      proxyReq.setHeader('app-id', PREMBLY_APP_ID);
    }
    if (PREMBLY_API_KEY) {
      proxyReq.setHeader('x-api-key', PREMBLY_API_KEY);
    }

    // Ensure the body is forwarded correctly if it has been parsed
    // (Though we are not using body-parser middleware before this, 
    // it's good practice to handle it if it were added later)
    if (req.body) {
      const bodyData = JSON.stringify(req.body);
      proxyReq.setHeader('Content-Length', Buffer.byteLength(bodyData));
      proxyReq.write(bodyData);
    }
  },
  onProxyRes: (proxyRes, req, res) => {
    // Optional: Log proxy responses
    // console.log(`Proxy response status: ${proxyRes.statusCode}`);
  },
  onError: (err, req, res) => {
    console.error('Proxy Error:', err);
    res.status(500).send('Proxy Error');
  }
});

// Middleware for the proxy route
app.use('/api/prembly', premblyProxy);

// Default route for health check
app.get('/', (req, res) => {
  res.send('Secure Prembly Proxy is running.');
});

app.listen(port, () => {
  console.log(`Proxy server listening at http://localhost:${port}`);
});

